SELECT neighborhood_name
FROM neighborhoods
WHERE median_income = (
    SELECT MAX(median_income)
    FROM neighborhoods
);

SELECT n.neighborhood_name
FROM neighborhoods n
WHERE n.median_income = (
    SELECT MAX(median_income)
    FROM neighborhoods
);

SELECT neighborhood_name
FROM neighborhoods
WHERE median_income > 100000;

SELECT neighborhood_name
FROM neighborhoods
WHERE median_income = (SELECT MAX(median_income) FROM neighborhoods);

SELECT MAX(median_income) AS highest_median_income
FROM neighborhoods
WHERE city = 'San Francisco';
